from datetime import datetime
from typing import List, Optional, Union

def earliest_event(events: List[Union[datetime, str]]) -> Optional[datetime]:
    """
    Returns the datetime object representing the earliest event in absolute time.

    If the input list contains strings, they are assumed to be ISO 8601 formatted
    strings and parsed into timezone-aware datetimes.

    If the list is empty, returns None.
    """
    if not events:
        return None

    def normalize_event(event):
        if isinstance(event, str):
            # ISO format string
            return datetime.fromisoformat(event)
        elif isinstance(event, datetime):
            if event.tzinfo is None:
                raise ValueError("All events must be timezone-aware.")
            return event
        else:
            raise TypeError("Events must be datetime instances or ISO 8601 strings.")

    earliest = None
    for event in events:
        normalized_event = normalize_event(event)
        if earliest is None or normalized_event < earliest:
            earliest = normalized_event

    return earliest
