from datetime import date, timedelta
from zoneinfo import ZoneInfo
import calendar

def add_years(d: date, n: int) -> date:
    """
    Add n years to a date.
    If the resulting day does not exist (e.g., Feb 29 on a non-leap year),
    clamp to Feb 28 of that year.
    """
    if d.month == 2 and d.day == 29:
        # Check if current year is a leap year
        is_current_leap = calendar.isleap(d.year)
        if n > 0:
            target_year = d.year + n
        elif n < 0:
            target_year = d.year + n
        else:
            return d

        is_target_leap = calendar.isleap(target_year)

        if is_current_leap and not is_target_leap:
            # Clamp to Feb 28
            return date(target_year, 2, 28)
        elif not is_current_leap and is_target_leap:
            # If we were on Feb 29 (impossible if not leap), this branch is logically unreachable
            # But if we had Feb 29 in a leap year and go back to a leap year, it's fine.
            # The only tricky case is going from a leap year Feb 29 to a non-leap year.
            # If we go from non-leap Feb 28 to a leap year, we stay Feb 28.
            # If we go from leap year Feb 29 to a leap year, we stay Feb 29.
            pass
        else:
            # Both are leap years or both are non-leap years.
            # If both are non-leap, we can't be on Feb 29, so this implies d must be Feb 29 in a leap year.
            # If both are leap, Feb 29 exists.
            pass

    # Standard addition
    try:
        return d.replace(year=d.year + n)
    except ValueError:
        # This happens if d.day is 29 and the new year is not a leap year
        return date(d.year + n, 2, 28)
