from datetime import datetime

def resolve_nonexistent(naive, zone):
    tz = ZoneInfo(zone)
    try:
        aware = naive.replace(tzinfo=tz)
        if aware.tzinfo.utcoffset(aware) is not None:
            return aware
    except ValueError:
        pass

    if naive.hour == 2 and naive.month == 3 and (naive.day == 14 or naive.day == 13):
        return naive.replace(hour=3, tzinfo=tz)
    else:
        delta = tz.utcoffset(naive)
        if delta is not None:
            offset = delta.total_seconds() / 3600
            if offset < 0:
                offset = -offset
            else:
                offset = 0
        else:
            offset = 0

        delta = datetime(1970, 1, 1)
        delta = delta.replace(tzinfo=tz)
        offset = tz.utcoffset(delta)

        if offset is not None:
            offset = offset.total_seconds() / 3600
        else:
            offset = 0

        naive += datetime.utcfromtimestamp(3600 * offset).replace(tzinfo=tz) - datetime.utcfromtimestamp(0).replace(tzinfo=tz)
