def resolve_nonexistent(naive, zone):
    tz = ZoneInfo(zone)
    try:
        aware = naive.replace(tzinfo=tz)
        return aware
    except ValueError:
        # If the time does not exist, roll it forward by the length of the gap
        start = naive
        end = naive
        while True:
            try:
                start = start.replace(tzinfo=tz)
                break
            except ValueError:
                start += tz.utcoffset(start).total_seconds()
        while True:
            try:
                end = end.replace(tzinfo=tz)
                break
            except ValueError:
                end += tz.utcoffset(end).total_seconds()
        gap = end - start
        return (naive + gap).replace(tzinfo=tz)
